
$(document).ready(function() {

  var x, i, j, l, ll, selElmnt, a, b, c;
  /* Look for any elements with the class "custom-select": */
  x = document.getElementsByClassName("custom-select");
  l = x.length;
  for (i = 0; i < l; i++) {
    selElmnt = x[i].getElementsByTagName("select")[0];
    ll = selElmnt.length;
    /* For each element, create a new DIV that will act as the selected item: */
    a = document.createElement("DIV");
    a.setAttribute("class", "select-selected");
    a.innerHTML = selElmnt.options[selElmnt.selectedIndex].innerHTML;
    x[i].appendChild(a);
    /* For each element, create a new DIV that will contain the option list: */
    b = document.createElement("DIV");
    b.setAttribute("class", "select-items select-hide");
    for (j = 1; j < ll; j++) {
      /* For each option in the original select element,
      create a new DIV that will act as an option item: */
      c = document.createElement("DIV");
      c.innerHTML = selElmnt.options[j].innerHTML;
      c.addEventListener("click", function(e) {
          /* When an item is clicked, update the original select box,
          and the selected item: */
          var y, i, k, s, h, sl, yl;
          s = this.parentNode.parentNode.getElementsByTagName("select")[0];
          sl = s.length;
          h = this.parentNode.previousSibling;
          for (i = 0; i < sl; i++) {
            if (s.options[i].innerHTML == this.innerHTML) {
              s.selectedIndex = i;
              h.innerHTML = this.innerHTML;
              y = this.parentNode.getElementsByClassName("same-as-selected");
              yl = y.length;
              for (k = 0; k < yl; k++) {
                y[k].removeAttribute("class");
              }
              this.setAttribute("class", "same-as-selected");
              break;
            }
          }
          h.click();
      });
      b.appendChild(c);
    }
    x[i].appendChild(b);
    a.addEventListener("click", function(e) {
      /* When the select box is clicked, close any other select boxes,
      and open/close the current select box: */
      e.stopPropagation();
      closeAllSelect(this);
      this.nextSibling.classList.toggle("select-hide");
      this.classList.toggle("select-arrow-active");
    });
  }

  function closeAllSelect(elmnt) {
    /* A function that will close all select boxes in the document,
    except the current select box: */
    var x, y, i, xl, yl, arrNo = [];
    x = document.getElementsByClassName("select-items");
    y = document.getElementsByClassName("select-selected");
    xl = x.length;
    yl = y.length;
    for (i = 0; i < yl; i++) {
      if (elmnt == y[i]) {
        arrNo.push(i)
      } else {
        y[i].classList.remove("select-arrow-active");
      }
    }
    for (i = 0; i < xl; i++) {
      if (arrNo.indexOf(i)) {
        x[i].classList.add("select-hide");
      }
    }
  }

  /* If the user clicks anywhere outside the select box,
  then close all select boxes: */
  document.addEventListener("click", closeAllSelect); 



});

var map;
function mapInit(coordinates, zoom) {

  // replace with your own API key
  const API_KEY = 'JPBYhy3irXQBcE3wM99rScDY8tWJ2ujSJyUfB0pw51g';

  /*
  We create the map and set its initial coordinates and zoom.
  See https://leafletjs.com/reference.html#map
  */
  map = L.map('map', {scrollWheelZoom: false}).setView(coordinates, zoom);

  // Povolíme zoom, když mapa získá fokus
  map.on('mousedown', function () {
      map.scrollWheelZoom.enable();
  });

  // Zakážeme zoom, když mapa ztratí fokus
  map.on('blur', function () {
      map.scrollWheelZoom.disable();
  });

  /*
  Then we add a raster tile layer with REST API Mapy.cz tiles
  See https://leafletjs.com/reference.html#tilelayer
  */
  L.tileLayer(`https://api.mapy.cz/v1/maptiles/basic/256/{ z}/{ x}/{ y}?apikey=${ API_KEY}`, {
    minZoom: 0,
    maxZoom: 19,
    attribution: '<a href="https://api.mapy.cz/copyright" target="_blank">&copy; Seznam.cz a.s. a další</a>',
  }).addTo(map);

  /*
  We also require you to include our logo somewhere over the map.
  We create our own map control implementing a documented interface,
  that shows a clickable logo.
  See https://leafletjs.com/reference.html#control
  */
  const LogoControl = L.Control.extend({
    options: {
      position: 'bottomleft',
    },

    onAdd: function (map) {
      const container = L.DomUtil.create('div');
      const link = L.DomUtil.create('a', '', container);

      link.setAttribute('href', 'http://mapy.cz/');
      link.setAttribute('target', '_blank');
      link.innerHTML = '<img src="https://api.mapy.cz/img/api/logo.svg" />';
      L.DomEvent.disableClickPropagation(link);

      return container;
    },
  });

  // finally we add our LogoControl to the map
  new LogoControl().addTo(map);
  console.log("mapa loadnuta");
  setInterval(function () {
     map.invalidateSize();
  }, 500);

}


if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/service-worker.js')
        .then(() => console.log('Service Worker registrován.'))
        .catch((error) => console.error('Service Worker selhal:', error));
}


async function copyToClipboard(text) {
  if (!navigator.clipboard) {
    // Fallback pro starší prohlížeče nebo méně bezpečné prostředí
    console.error('API schránky není k dispozici.');
    return false;
  }
  try {
    await navigator.clipboard.writeText(text);
    console.log('Text byl úspěšně zkopírován do schránky!');
    alert("Zkopírováno do schránky");
    return true;
  } catch (err) {
    console.error('Selhalo zkopírování textu: ', err);
    return false;
  }
}

function getCookie(cname) {
  let name = cname + "=";
  let decodedCookie = decodeURIComponent(document.cookie);
  let ca = decodedCookie.split(';');
  for(let i = 0; i <ca.length; i++) {
    let c = ca[i];
    while (c.charAt(0) == ' ') {
      c = c.substring(1);
    }
    if (c.indexOf(name) == 0) {
      return c.substring(name.length, c.length);
    }
  }
  return "";
}

